import { Platform } from 'react-native';

const apiUrl = 'https://api.example.com';

export const AuthService = {
  login: async (username, password) => {
    const response = await fetch(`${apiUrl}/auth/login`, {
      method: 'POST',
      headers: {
        Accept: 'application/json',
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ username, password }),
    });

    const json = await response.json();
    if (response.ok) {
      // Handle successful login and store the token in a secure way
      return json.token;
    } else {
      throw new Error(json.message);
    }
  },
};

export const ProfileService = {
  getCurrentUserProfile: async (token) => {
    const response = await fetch(`${apiUrl}/profile`, {
      method: 'GET',
      headers: {
        Accept: 'application/json',
        'Content-Type': 'application/json',
        Authorization: `Bearer ${token}`,
      },
    });

    const json = await response.json();
    if (response.ok) {
      return json;
    } else {
      throw new Error(json.message);
    }
  },

  updateUserProfile: async (token, updatedProfile) => {
    const response = await fetch(`${apiUrl}/profile`, {
      method: 'PUT',
      headers: {
        Accept: 'application/json',
        'Content-Type': 'application/json',
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify(updatedProfile),
    });

    const json = await response.json();
    if (response.ok) {
      return json;
    } else {
      throw new Error(json.message);
    }
  },
};

// For cross-platform compatibility, you can use axios or another library that abstracts the differences between iOS and Android networking.
if (Platform.OS === 'android') {
  global.fetch = require('node-fetch'); // Use node-fetch for Android
}